package sarama

import (
	"testing"

	"github.com/pierrec/lz4/v4"
)

func TestLZ4CompressionUsesSmallBlockSize(t *testing.T) {
	// Ensure our pooled writer is configured to not use the lz4/v4 default (4MB)
	// block size, which can lead to excessive per-request decompression buffers
	// on Kafka brokers.
	w := lz4WriterPool.Get().(*lz4.Writer)
	defer lz4WriterPool.Put(w)

	size := w.BlockSize()
	if size != lz4.Block64Kb {
		t.Fatalf("expected LZ4 writer block size %v, got %v", lz4.Block64Kb, size)
	}
}

