package sarama

import "testing"

func TestLZ4CompressionDoesNotUseDefault4MBBlockSize(t *testing.T) {
	// We can’t introspect lz4/v4 Writer options directly, but we *can* assert
	// on the output frame header: the max block size is encoded there.
	payload := []byte("hello world")

	compressed, err := lz4Compress(payload)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(compressed) < 8 {
		t.Fatalf("compressed output too small: %d", len(compressed))
	}

	// lz4 frame format: bytes[4:7] is FLG+BD+HC.
	// BD (byte 5, 0-based) encodes max block size.
	bd := compressed[5]
	if bd == 0x70 {
		// 0x70 corresponds to 4MB blocks (Block4Mb) in the LZ4 frame spec.
		t.Fatalf("lz4 writer is using 4MB block size (BD=0x70); expected smaller block size")
	}
}

